     9→:root {
    10→  /* Warm/Paper-like background for "Elegant" feel */
    11→  --background: #fafaf9; /* Stone 50 */
    12→  --foreground: #44403c; /* Stone 700 */
    13→  --heading: #1c1917; /* Stone 900 */
    14→  --accent: #059669; /* Emerald 600 */
    15→  --accent-hover: #047857; /* Emerald 700 */
    16→  --muted: #78716c; /* Stone 500 - Improved contrast */
    17→  --code-fg: #1c1917; /* Stone 900 - High contrast neutral */
    18→}
    19→
    20→.dark {
    21→  --background: #292524; /* Stone 800 */
    22→  --foreground: #f5f5f4; /* Stone 100 */
    23→  --heading: #fafaf9; /* Stone 50 */
    24→  --accent: #34d399; /* Emerald 400 */
    25→  --accent-hover: #10b981; /* Emerald 500 */
    26→  --muted: #a8a29e; /* Stone 400 - Good contrast on dark */
    27→  --code-fg: #e7e5e4; /* Stone 200 - High contrast neutral */
    28→}
    29→
    30→/* Palette Overrides */
    31→/* Blue */
    32→[data-palette="blue"] {
    33→  --accent: #2563eb; /* Blue 600 */
    34→  --accent-hover: #1d4ed8;
    35→}
    36→.dark[data-palette="blue"] {
    37→  --accent: #60a5fa; /* Blue 400 */
    38→  --accent-hover: #3b82f6;
    39→}
    40→
    41→/* Rose */
    42→[data-palette="rose"] {
    43→  --accent: #e11d48; /* Rose 600 */
    44→  --accent-hover: #be123c;
    45→}
    46→.dark[data-palette="rose"] {
    47→  --accent: #fb7185; /* Rose 400 */
    48→  --accent-hover: #f43f5e;
    49→}
    50→
    51→/* Amber */
    52→[data-palette="amber"] {
    53→  --accent: #d97706; /* Amber 600 */
    54→  --accent-hover: #b45309;
    55→}
    56→.dark[data-palette="amber"] {
    57→  --accent: #fbbf24; /* Amber 400 */
    58→  --accent-hover: #f59e0b;
    59→}
    60→
    61→/* Wikilink styles */
    62→.wikilink {
    63→  text-decoration: none;
    64→  transition: color 0.15s;
    65→}
    66→.wikilink::before,
    67→.wikilink::after {
    68→  font-family: var(--font-mono);
    69→  font-size: 0.72em;
    70→  opacity: 0.45;
    71→  vertical-align: 0.08em;
    72→  transition: opacity 0.15s;
    73→}
    74→.wikilink::before { content: '[['; }
    75→.wikilink::after  { content: ']]'; }
    76→.wikilink--resolved {
    77→  color: var(--accent);
    78→}
    79→.wikilink--resolved:hover,
    80→.wikilink--resolved:focus-visible {
    81→  color: var(--accent-hover);
    82→  text-decoration: underline;
    83→  outline: none;
    84→}
    85→.wikilink--resolved:focus-visible {
    86→  outline: 2px solid var(--accent);
    87→  outline-offset: 2px;
    88→  border-radius: 2px;
    89→}
    90→.wikilink--resolved:hover::before,
    91→.wikilink--resolved:hover::after,
    92→.wikilink--resolved:focus-visible::before,
    93→.wikilink--resolved:focus-visible::after {
    94→  opacity: 0.75;
    95→}
    96→.wikilink--broken {
    97→  color: var(--muted);
    98→  text-decoration: underline dashed;
    99→  cursor: default;
   100→}
   101→
   102→/* PrismJS Syntax Highlighting Custom Theme */
   103→code[class*="language-"],
   104→pre[class*="language-"] {
   105→  color: var(--foreground);
   106→  text-shadow: none;
   107→  font-family: var(--font-mono);
   108→  font-size: 0.9em;
   109→  direction: ltr;
   110→  text-align: left;
   111→  white-space: pre;
   112→  word-spacing: normal;
   113→  word-break: normal;
   114→  line-height: 1.5;
   115→  tab-size: 4;
   116→  hyphens: none;
   117→}
   118→
   119→.token.comment,
   120→.token.prolog,
   121→.token.doctype,
   122→.token.cdata {
   123→  color: var(--muted);
   124→  font-style: italic;
   125→}
   126→
   127→.token.punctuation {
